#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline double max(const double &x,const double &y){return x<y?y:x;}
const int N=1e5+10;double mx[N<<2];int sm[N<<2],n;
inline int update(const int &cur,const double &w,const int &l,const int &r)
{
	if(mx[cur]<=w)return 0;if(l==r)return w<mx[cur];int mid=(l+r)>>1;
	return w<mx[cur<<1]?update(cur<<1,w,l,mid)+sm[cur]-sm[cur<<1]:update(cur<<1|1,w,mid+1,r);
}
inline void mdy(const int &pos,const double &w,const int &l=1,const int &r=n,const int &cur=1)
{
	if(l==r)return mx[cur]=w,sm[cur]=1,void();int mid=(l+r)>>1;
	pos<=mid?mdy(pos,w,l,mid,cur<<1):mdy(pos,w,mid+1,r,cur<<1|1);
	mx[cur]=max(mx[cur<<1],mx[cur<<1|1]); 
	sm[cur]=sm[cur<<1]+update(cur<<1|1,mx[cur<<1],mid+1,r);
}
int main(){n=read();int Q=read();while(Q--){int pos=read();double w=1.0*read()/pos;mdy(pos,w);print(sm[1]);putchar('\n');}}
